// Create parent RelativeLayout
RelativeLayout relLayout = new RelativeLayout(this);
relLayout.setLayoutParams(new RelativeLayout.LayoutParams(
 RelativeLayout.LayoutParams.MATCH_PARENT,
 RelativeLayout.LayoutParams.MATCH_PARENT));

// Username EditText
EditText etUsername = new EditText(this);
RelativeLayout.LayoutParams userParams = new RelativeLayout.LayoutParams(
 RelativeLayout.LayoutParams.MATCH_PARENT,
 RelativeLayout.LayoutParams.WRAP_CONTENT);
userParams.addRule(RelativeLayout.CENTER_HORIZONTAL);
userParams.addRule(RelativeLayout.ALIGN_PARENT_TOP);
relLayout.addView(etUsername, userParams);

// Password EditText (below username)
EditText etPassword = new EditText(this);
RelativeLayout.LayoutParams passParams = new RelativeLayout.LayoutParams(
 RelativeLayout.LayoutParams.MATCH_PARENT,
 RelativeLayout.LayoutParams.WRAP_CONTENT);
passParams.addRule(RelativeLayout.BELOW, etUsername.getId());
passParams.addRule(RelativeLayout.CENTER_HORIZONTAL);
relLayout.addView(etPassword, passParams);

// Create TableLayout with stretching
TableLayout table = new TableLayout(this);
table.setStretchAllColumns(true);

// Add header row
TableRow headerRow = new TableRow(this);
String[] headers = {"x", "1", "2", "3"};
for (String header : headers) {
 TextView tv = new TextView(this);
 tv.setText(header);
 headerRow.addView(tv);
}
table.addView(headerRow);

// Add data rows
for (int i = 1; i <= 3; i++) {
 TableRow row = new TableRow(this);
 TextView label = new TextView(this);
 label.setText(String.valueOf(i));
 row.addView(label);

 for (int j = 1; j <= 3; j++) {
 TextView cell = new TextView(this);
 cell.setText(String.valueOf(i * j));
 row.addView(cell);
 }
 table.addView(row);
}
